%======================
% Side A – Sensory Map
%======================
\begin{tikzpicture}[x=1cm,y=1cm]
  % GRID BACKGROUND
  \draw[step=1cm,very thin,gray!50] (0,0) grid (\GridSize,\GridSize);

  % REGISTRATION TICKS
  \foreach \x/\y in {0/0, \GridSize/0, 0/\GridSize, \GridSize/\GridSize}{
    \draw[black] (\x,\y) ++(-0.2,0) -- ++(0.4,0);
    \draw[black] (\x,\y) ++(0,-0.2) -- ++(0,0.4);
  }

  % AXIS-NORTH SPINE
  \draw[line width=1pt,red] 
    (\GridSize/2,-1) --
    ++({\AxisNorthAngle+90}:\GridSize+2);

  % COMPASS ROSE
  \begin{scope}[shift={(\GridSize-1,\GridSize-1)}]
    \draw[gray!50] (0,0) circle (0.8cm);
    \foreach \ang in {0,45,...,315} {
      \draw[gray!50] (0,0) -- (\ang:0.8cm);
    }
    % True North
    \draw[thick] (0,0) -- (90:0.8cm) node[above] {\tiny N};
    % Axis-North
