  % LEGEND
  \begin{scope}[shift={(\GridSize+0.5, \GridSize-1.5)}]
    \node[anchor=west,text width=6cm,align=left] at (0,0) {\scriptsize
    {\bf Symbol Legend:}\\
    $\bullet$ size = Volume/Intensity \\
    Left/Right = Low/High pitch \\
    {\footnotesize ---} = Connection line \\
    $\triangle$ = Triad \\
    $\star$ = Warm triangle \\
    $\approx$ = Vibration \\
    $\lightning$ = Key change \\
    $\bigcirc$ = Felt/unheard \\
    $\cdots$ = Carrier wave \\
    gap~$\cdot$/--- = short/long gap
    };
  \end{scope}

  % GAP ENCODING BOX
  \draw[gray!50] (0,-2.2) rectangle (\GridSize/2,-3.7);
  \node[anchor=west] at (0.1,-2.3) {\scriptsize Gap Encoding:};
  \node[anchor=west] at (0.1,-2.7) {\scriptsize [ ] Short gap $(\cdot)$ Count:};
  \node[anchor=west] at (0.1,-3.1) {\scriptsize [ ] Long gap $(\textendash)$ Count:};
  \node[anchor=west] at (0.1,-3.5) {\scriptsize Sequence: \_\_\_\_\_\_\_\_\_};

  % TRIANGLE VECTOR BOX
  \draw[gray!50] (\GridSize/2+0.2,-2.2) rectangle (\GridSize,-3.7);
  \node[anchor=west] at (\GridSize/2+0.3,-2.3) {\scriptsize Triangle Vectors:};
  \node[anchor=west] at (\GridSize/2+0.3,-2.7) {\scriptsize Coordinates:};
  \node[anchor=west] at (\GridSize/2+0.3,-3.1) {\scriptsize Orientation vs Axis-N:};
\end{tikzpicture}

\newpage

%======================
% Side B – Tasks/Reflection
%======================
\begin{tikzpicture}[x=1cm,y=1cm]
  \node[anchor=west] at (0,9.5) {\small Date / Time / Location:};
  \node[anchor=west] at (0,8.8) {\small Start Signal:};

  \node[anchor=west] at (0,8) {\bf Micro-Sprint Tasks:};
  \foreach \i in {1,...,3} {
